(function(){'use strict';const is=()=>{if(document.getElementById('jf-header-streams-styles'))return;const s=document.createElement('style');s.id='jf-header-streams-styles';s.textContent='#jf-header-streams{display:flex;align-items:center;justify-content:center;margin-right:8px;padding:0 10px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:6px;color:#fff;cursor:pointer;transition:all .3s ease;font-family:"Inter",system-ui,sans-serif;opacity:.6;height:30px}#jf-header-streams:hover{background:rgba(255,255,255,.1);opacity:1}#jf-header-streams.jf-streams-active{opacity:1;color:#00a4dc;background:rgba(0,164,220,.1);border-color:rgba(0,164,220,.3);box-shadow:0 0 10px rgba(0,164,220,.15)}#jf-header-streams .jf-hs-count{font-size:.95em;font-weight:600;margin-left:6px}#jf-header-streams .jf-hs-icon{font-size:1.4em !important;transition:transform .2s ease}#jf-header-streams.jf-streams-active .jf-hs-icon{animation:hs-pulse-glow 2s infinite alternate}@keyframes hs-pulse-glow{0%{text-shadow:0 0 5px rgba(0,164,220,.2)}100%{text-shadow:0 0 15px rgba(0,164,220,.8)}}#jf-more-menu #jf-header-streams::after{display:none !important;content:none !important}#rpg-nav-btn{order:-3 !important}.headerSearchButton{order:-2 !important}';document.head.appendChild(s);};const fas=async()=>{if(typeof ApiClient==='undefined')return 0;try{const s=await ApiClient.getJSON(ApiClient.getUrl('Sessions'));let c=0;for(let i=0;i<s.length;i++){if(s[i].NowPlayingItem&&(!s[i].PlayState||!s[i].PlayState.IsPaused))c++;}return c;}catch(e){console.error("Stream Counter Error:",e);return-1;}};const us=async()=>{const c=document.getElementById('jf-header-streams');if(!c||document.hidden){setTimeout(us,2000);return;}const n=await fas();if(n===-1){c.innerHTML='<span class="material-icons jf-hs-icon">error_outline</span><span class="jf-hs-count">Err</span>';c.title="Failed to fetch sessions";c.classList.remove('jf-streams-active');}else if(n===0){c.innerHTML='<span class="material-icons jf-hs-icon">visibility_off</span><span class="jf-hs-count">0</span>';c.title="No active streams";c.classList.remove('jf-streams-active');}else{c.innerHTML=`<span class="material-icons jf-hs-icon">visibility</span><span class="jf-hs-count">${n}</span>`;c.title=`${n} Active Stream${n>1?'s':''}`;c.classList.add('jf-streams-active');}setTimeout(us,15000);};const tih=()=>{if(document.getElementById('jf-header-streams'))return;const hr=document.querySelector('.headerRight');if(!hr)return;const c=document.createElement('div');c.id='jf-header-streams';c.className='headerButton';c.setAttribute('data-jf-order-desktop','-1');c.setAttribute('data-jf-order-mobile','-1');c.innerHTML='<span class="material-icons jf-hs-icon" style="opacity: 0.5;">sync</span><span class="jf-hs-count">...</span>';c.addEventListener('click',()=>{window.location.hash='#!/dashboard.html';});hr.insertBefore(c,hr.firstChild);};const i=()=>{is();setInterval(tih,1000);tih();us();};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',i);}else{i();}})();
